        if offset.is_some() {
            return ESPIPE as usize;
        }
        let _inner = self.inner.lock();
        for buffer in user_buffer.buffers.iter() {
            match core::str::from_utf8(*buffer) {
                Ok(content) => print!("{}", content),
                Err(_) => warn!("[tty_write] Non-UTF8 charaters: {:?}", *buffer),
